import { describe, expect, it } from 'vitest';

import {
  computePayloadOffset,
  parseKnotHeaderFromBytes,
} from '../src/knot-header';

/**
 * Contract tests for the .knot file format.
 *
 * Why this file exists:
 *   The encoder (open-source/bitwise/scripts/encode-llama-knot.ts buildKnotBuffer)
 *   and the canonical reader (open-source/gnosis/distributed-inference-host/
 *   src/knot-header.ts computePayloadOffset) drifted out of agreement for
 *   months. The encoder was writing the *padded* metadata length into the
 *   `metaLen` u32, while the reader's formula `((10 + metaLen + 3) & ~3) + 1`
 *   assumes `metaLen` is the *unpadded* JSON byte length.
 *
 *   For most metadata sizes that placed the FP64 codec marker (0x40) one
 *   byte inside the tensor payload, and put the payload offset one byte
 *   past the marker. Every Q4_K block read from the resulting knots was
 *   shifted by one byte and silently produced corrupt logits.
 *
 *   The fix made the encoder write the *unpadded* length and emit the NUL
 *   pad *outside* the JSON. These tests pin that contract from the
 *   reader's perspective so a future encoder change can never re-introduce
 *   the off-by-one without lighting up red.
 *
 * Canonical layout (all multi-byte ints little-endian):
 *
 *   bytes 0..3                 KNOT magic
 *   bytes 4..5                 u16 version (LE)
 *   bytes 6..9                 u32 metaLen (UNPADDED, LE)
 *   bytes 10..10+metaLen       JSON metadata (no padding)
 *   bytes 10+metaLen..align-1  NUL pad to next 4-byte boundary (0..3 bytes)
 *   byte  align                FP64 codec marker (0x40)
 *   bytes align+1..            tensor payload
 *
 *   where align = (10 + metaLen + 3) & ~3 and the reader returns
 *   `align + 1` from computePayloadOffset(metaLen).
 */

const KNOT_MAGIC = new TextEncoder().encode('KNOT');
const FP64_MARKER = 0x40;
const HEADER_PREFIX_BYTES = 10;
const VERSION = 1;

/**
 * In-test re-implementation of `buildKnotBuffer` from
 * open-source/bitwise/scripts/encode-llama-knot.ts. We rebuild it inline
 * here so the test does not depend on the bitwise scripts package
 * (different workspace, mixed Node/Buffer types). The layout it produces
 * MUST byte-for-byte match the encoder's output for the contract test to
 * be meaningful — if the encoder changes, this helper has to change too,
 * which is exactly the failure signal we want when contracts drift.
 *
 * Returns the full buffer plus the bookkeeping the test asserts against.
 */
interface BuiltCanonicalKnot {
  bytes: Uint8Array;
  metadataJson: string;
  metadataBytes: Uint8Array;
  metadataLength: number;
  paddingBytes: number;
  alignedMetaEnd: number; // == payloadOffset - 1, where the FP64 marker sits
  payloadOffset: number;
  payload: Uint8Array;
}

function buildCanonicalKnot(
  metadata: Record<string, unknown>,
  payload: Uint8Array,
): BuiltCanonicalKnot {
  const metadataJson = JSON.stringify(metadata);
  const metadataBytes = new TextEncoder().encode(metadataJson);
  const metadataLength = metadataBytes.length;

  // padding is 0..3 bytes that round (10 + metaLen) up to a 4-byte boundary.
  const paddingBytes = (4 - ((HEADER_PREFIX_BYTES + metadataLength) % 4)) % 4;
  const alignedMetaEnd =
    (HEADER_PREFIX_BYTES + metadataLength + 3) & ~3;
  const payloadOffset = alignedMetaEnd + 1;

  const totalSize = payloadOffset + payload.length;
  const out = new Uint8Array(totalSize);
  // Magic
  out.set(KNOT_MAGIC, 0);
  // Version + metaLen via DataView
  const view = new DataView(out.buffer, out.byteOffset, out.byteLength);
  view.setUint16(4, VERSION, /* littleEndian */ true);
  view.setUint32(6, metadataLength, /* littleEndian */ true);
  // Metadata JSON (no in-JSON padding)
  out.set(metadataBytes, HEADER_PREFIX_BYTES);
  // NUL pad slots are already zero-initialized by Uint8Array allocation.
  // Codec marker
  out[alignedMetaEnd] = FP64_MARKER;
  // Payload
  out.set(payload, payloadOffset);

  return {
    bytes: out,
    metadataJson,
    metadataBytes,
    metadataLength,
    paddingBytes,
    alignedMetaEnd,
    payloadOffset,
    payload,
  };
}

/**
 * Build a buffer the OLD broken way: space-pad the JSON to the 4-byte
 * boundary, then write the *padded* length into the metaLen u32. This is
 * what the pre-fix encoder did. We keep it on hand for the regression
 * guard test.
 */
function buildBrokenKnotOldEncoder(
  metadata: Record<string, unknown>,
  payload: Uint8Array,
): Uint8Array {
  const metadataJson = JSON.stringify(metadata);
  // Pad JSON content with ASCII space until (10 + len) % 4 === 0. The old
  // encoder relied on JSON.parse tolerating trailing whitespace, which is
  // why this ever worked at all when paddedLen happened to equal
  // unpaddedLen mod 4.
  let padded = metadataJson;
  while ((HEADER_PREFIX_BYTES + padded.length) % 4 !== 0) {
    padded += ' ';
  }
  const metadataBytes = new TextEncoder().encode(padded);
  const paddedLen = metadataBytes.length;

  const totalSize = HEADER_PREFIX_BYTES + paddedLen + 1 + payload.length;
  const out = new Uint8Array(totalSize);
  out.set(KNOT_MAGIC, 0);
  const view = new DataView(out.buffer, out.byteOffset, out.byteLength);
  view.setUint16(4, VERSION, true);
  // The bug: write paddedLen, not unpadded.
  view.setUint32(6, paddedLen, true);
  out.set(metadataBytes, HEADER_PREFIX_BYTES);
  // Old encoder put the marker right after the (padded) JSON, no extra NUL pad.
  out[HEADER_PREFIX_BYTES + paddedLen] = FP64_MARKER;
  out.set(payload, HEADER_PREFIX_BYTES + paddedLen + 1);
  return out;
}

/**
 * Each test picks a `tag` length that hits a different `(10 + metaLen) % 4`
 * residue. With metadata = {tensors:{}, tag:'x'.repeat(N)} the JSON byte
 * length L is 23 + N, so:
 *
 *   N=0 -> L=23, (10+L)%4 = 1, padding = 3 (max NUL pad)
 *   N=1 -> L=24, (10+L)%4 = 2, padding = 2
 *   N=2 -> L=25, (10+L)%4 = 3, padding = 1
 *   N=3 -> L=26, (10+L)%4 = 0, padding = 0 (exactly aligned)
 *
 * Together these exercise every NUL-pad arity the format permits.
 */
const RESIDUE_FIXTURES: Array<{
  tagLen: number;
  expectedJsonLen: number;
  expectedPadding: number;
  residue: number;
}> = [
  { tagLen: 0, expectedJsonLen: 23, expectedPadding: 3, residue: 1 },
  { tagLen: 1, expectedJsonLen: 24, expectedPadding: 2, residue: 2 },
  { tagLen: 2, expectedJsonLen: 25, expectedPadding: 1, residue: 3 },
  { tagLen: 3, expectedJsonLen: 26, expectedPadding: 0, residue: 0 },
];

describe('.knot encoder/reader contract — every (10 + metaLen) % 4 residue', () => {
  for (const fx of RESIDUE_FIXTURES) {
    it(`round-trips metadata at tagLen=${fx.tagLen} (jsonLen=${fx.expectedJsonLen}, residue=${fx.residue}, NUL pad=${fx.expectedPadding})`, () => {
      /**
       * Why this test:
       *   Pin the contract that the encoder writes the *unpadded* JSON
       *   byte length and that any padding sits *outside* the JSON. If a
       *   future encoder regression ever switches back to padded length
       *   (the old bug) or to in-JSON whitespace padding, the assertion
       *   on bytes[10..10+metaLen] parsing without trim catches it.
       */
      const metadata = {
        tensors: {} as Record<string, unknown>,
        tag: 'x'.repeat(fx.tagLen),
      };
      // Tiny payload so we can probe both "byte at payloadOffset" and the
      // edge byte before it. Distinct values so an off-by-one read shows up.
      const payload = new Uint8Array([0xab, 0xcd, 0xef, 0x99]);

      const built = buildCanonicalKnot(metadata, payload);

      // Sanity: the helper itself produced what the test fixture promised.
      expect(built.metadataLength).toBe(fx.expectedJsonLen);
      expect(built.paddingBytes).toBe(fx.expectedPadding);

      const header = parseKnotHeaderFromBytes(built.bytes);

      // 1. metadataLength is the UNPADDED JSON byte length, not a rounded value.
      expect(header.metadataLength).toBe(fx.expectedJsonLen);
      expect(header.metadataLength).toBe(built.metadataBytes.length);

      // 2. Parsed metadata equals the original — no whitespace pollution,
      //    no missing fields. JSON.stringify is canonical so direct
      //    deep-equal works.
      expect(header.metadata).toEqual(metadata);

      // 3. The byte immediately before payloadOffset is the FP64 marker.
      //    This is the bug's primary symptom: when it drifted, this byte
      //    used to be 0x00 (a NUL pad byte) or the first byte of payload
      //    instead of 0x40.
      const expectedPayloadOffset = computePayloadOffset(fx.expectedJsonLen);
      expect(header.payloadOffset).toBe(expectedPayloadOffset);
      expect(built.bytes[header.payloadOffset - 1]).toBe(FP64_MARKER);
      expect(header.codecMarker).toBe(FP64_MARKER);

      // 4. The byte at payloadOffset is the first byte of the payload.
      //    This is the dual of (3): if the marker is wrong we usually
      //    also see the wrong first-payload-byte.
      expect(built.bytes[header.payloadOffset]).toBe(payload[0]);

      // 5. Regression guard against the old encoder's space-padding:
      //    bytes[10..10+metaLen] must parse as JSON *without* any
      //    rstrip-trailing-whitespace step. If a future encoder ever
      //    reverts to in-JSON ASCII-space padding, the metadataLength
      //    will exceed the JSON's true byte length and JSON.parse on the
      //    raw window will either throw or produce a string with
      //    trailing-space contamination in the `tag` field.
      const metaWindow = built.bytes.subarray(
        HEADER_PREFIX_BYTES,
        HEADER_PREFIX_BYTES + header.metadataLength,
      );
      const rawJson = new TextDecoder('utf-8').decode(metaWindow);
      expect(rawJson).toBe(built.metadataJson);
      expect(rawJson.endsWith(' ')).toBe(false);
      const reparsed = JSON.parse(rawJson) as typeof metadata;
      expect(reparsed.tag).toBe(metadata.tag); // no trailing-space pollution
      expect(reparsed.tag.endsWith(' ')).toBe(false);
    });
  }
});

describe('.knot regression guard — old broken encoder layout', () => {
  it('rejects or visibly misaligns a buffer built the old (paddedLen) way', () => {
    /**
     * Why this test:
     *   Document, in code, that the bug is fixable from the encoder side
     *   and that the canonical reader is the source of truth for the
     *   layout. We do not assert "throws" because the broken layout can
     *   sometimes squeak past JSON.parse (the old encoder added trailing
     *   ASCII spaces, which JSON.parse silently tolerates). What we DO
     *   assert is that, if it parses, the FP64 marker is no longer at
     *   `payloadOffset - 1` — proving the reader and that buffer disagree
     *   on where the payload begins.
     *
     *   The diagnostic detail printed when this assertion would fail is
     *   the byte AT payloadOffset and the byte at payloadOffset - 1 so a
     *   future engineer staring at a corrupted Q4_K block can see exactly
     *   which side of the boundary slipped.
     */
    // Pick a metadata size where the old encoder actively pads — i.e.
    // residue != 0 — so paddedLen != unpaddedLen and the bug bites.
    const metadata = { tensors: {}, tag: 'x' }; // L=24, residue 2, padding 2
    const payload = new Uint8Array([0xab, 0xcd, 0xef, 0x99]);

    const broken = buildBrokenKnotOldEncoder(metadata, payload);

    let caughtMessage: string | null = null;
    let parsed: ReturnType<typeof parseKnotHeaderFromBytes> | null = null;
    try {
      parsed = parseKnotHeaderFromBytes(broken);
    } catch (err) {
      caughtMessage = (err as Error).message;
    }

    if (caughtMessage !== null) {
      // Acceptable outcome: reader rejects the broken buffer outright.
      // We still want SOME signal so the test doesn't pass trivially.
      expect(caughtMessage.length).toBeGreaterThan(0);
      return;
    }

    // Parse succeeded despite the broken layout. Surface the diagnostic
    // bytes so the failure message tells a future engineer exactly what
    // is misaligned. We expect the marker to be in the wrong place: the
    // reader's payloadOffset (computed from the stored *padded* metaLen
    // as if it were unpadded) overshoots the real marker, so
    // bytes[payloadOffset - 1] is now the codec marker only by coincidence.
    expect(parsed).not.toBeNull();
    const p = parsed!;
    const byteBefore = broken[p.payloadOffset - 1];
    const byteAt = broken[p.payloadOffset];

    // Either the marker isn't where the reader expects (the bug's
    // symptom), or — if by coincidence both bytes happen to align — at
    // minimum the metadata length the reader extracted does NOT match
    // the unpadded JSON byte length. We assert at least one of those
    // disagreements holds, with diagnostic info baked into the message.
    const unpaddedJsonLen = new TextEncoder().encode(JSON.stringify(metadata))
      .length;

    const markerWrong = byteBefore !== FP64_MARKER;
    const lengthWrong = p.metadataLength !== unpaddedJsonLen;

    expect(
      markerWrong || lengthWrong,
      `old broken encoder produced a buffer the reader appears to accept; ` +
        `byteBefore(payloadOffset-1)=0x${byteBefore?.toString(16)} ` +
        `byteAt(payloadOffset)=0x${byteAt?.toString(16)} ` +
        `reader.metadataLength=${p.metadataLength} ` +
        `unpaddedJsonLen=${unpaddedJsonLen} — ` +
        `if both fields look correct the bug is back; investigate ` +
        `buildKnotBuffer in encode-llama-knot.ts.`,
    ).toBe(true);
  });
});

describe('.knot boundary cases', () => {
  it('computePayloadOffset(0) lands at byte 13 (degenerate metaLen=0)', () => {
    /**
     * Why this test:
     *   metaLen = 0 is impossible for a valid knot (the reader requires a
     *   `tensors` field) but it is a useful edge for the offset math
     *   alone. (10 + 0 + 3) & ~3 = 12, +1 = 13. Pinning this independent
     *   of any encoder makes the math self-checking.
     */
    expect(computePayloadOffset(0)).toBe(13);
  });

  it('handles metaLen exactly aligned (no NUL pad needed)', () => {
    /**
     * Why this test:
     *   When (10 + metaLen) % 4 === 0 the encoder emits zero NUL pad
     *   bytes and the FP64 marker sits at byte 10 + metaLen exactly.
     *   The reader and encoder must still agree on the payload offset
     *   and the marker location in this zero-padding regime — the
     *   degenerate case where the old paddedLen bug coincidentally did
     *   not bite.
     */
    // tag length 3 -> JSON length 26, (10+26)%4 = 0
    const metadata = { tensors: {}, tag: 'xxx' };
    const payload = new Uint8Array([0x11, 0x22, 0x33]);
    const built = buildCanonicalKnot(metadata, payload);

    expect(built.paddingBytes).toBe(0);
    expect(built.metadataLength).toBe(26);

    const header = parseKnotHeaderFromBytes(built.bytes);
    expect(header.metadataLength).toBe(26);
    expect(header.payloadOffset).toBe(computePayloadOffset(26));
    expect(header.payloadOffset).toBe(10 + 26 + 1); // align == 10+metaLen, +1 for marker
    expect(built.bytes[header.payloadOffset - 1]).toBe(FP64_MARKER);
    expect(built.bytes[header.payloadOffset]).toBe(0x11);
  });

  it('handles metaLen requiring max NUL pad (3 bytes)', () => {
    /**
     * Why this test:
     *   When (10 + metaLen) % 4 === 1 the encoder must emit 3 NUL pad
     *   bytes, the largest pad the format supports. The bytes between
     *   metadata end and the FP64 marker must all be 0x00, the marker
     *   must sit at the aligned boundary, and the payload must start
     *   one byte after.
     */
    // tag length 0 -> JSON length 23, (10+23)%4 = 1, padding = 3
    const metadata = { tensors: {}, tag: '' };
    const payload = new Uint8Array([0x77, 0x88, 0x99]);
    const built = buildCanonicalKnot(metadata, payload);

    expect(built.paddingBytes).toBe(3);
    expect(built.metadataLength).toBe(23);

    const header = parseKnotHeaderFromBytes(built.bytes);
    expect(header.metadataLength).toBe(23);
    expect(header.payloadOffset).toBe(computePayloadOffset(23));

    const padStart = HEADER_PREFIX_BYTES + 23; // 33
    const padEnd = header.payloadOffset - 1; // marker position == 36
    // All three pad bytes are zero.
    for (let i = padStart; i < padEnd; i += 1) {
      expect(built.bytes[i]).toBe(0x00);
    }
    expect(padEnd - padStart).toBe(3);
    // Marker and payload land where the formula says.
    expect(built.bytes[padEnd]).toBe(FP64_MARKER);
    expect(built.bytes[header.payloadOffset]).toBe(0x77);
  });
});
